public interface IPaymentGateway
{
    Task<PaymentResult> ChargeAsync(decimal amount, string token, CancellationToken ct);
}

// Adapter wrapping the third-party Stripe SDK (Infrastructure layer)
public class StripePaymentAdapter : IPaymentGateway
{
    private readonly StripeClient _stripe; // vendor SDK type stays here
    public StripePaymentAdapter(StripeClient stripe) => _stripe = stripe;

    public async Task<PaymentResult> ChargeAsync(decimal amount, string token, CancellationToken ct)
    {
        var charge = await _stripe.Charges.CreateAsync(
            new ChargeCreateOptions { Amount = (long)(amount * 100), Source = token }, ct);
        return new PaymentResult(charge.Status == "succeeded", charge.Id);
    }
}

// Facade: one simple call hides a multi-step subsystem
public class CheckoutFacade
{
    private readonly IInventoryService _inventory;
    private readonly IPaymentGateway _payment;
    private readonly IShippingService _shipping;
    private readonly INotificationService _notify;

    public async Task<OrderResult> PlaceOrderAsync(OrderRequest req, CancellationToken ct)
    {
        await _inventory.ReserveAsync(req.Items, ct);
        var payment = await _payment.ChargeAsync(req.Total, req.Token, ct);
        var shipment = await _shipping.ScheduleAsync(req.Address, ct);
        await _notify.OrderConfirmedAsync(req.CustomerId, ct);
        return new OrderResult(payment.TransactionId, shipment.TrackingId);
    }
}

