public abstract class DataImporter
{
    // Template method: fixed skeleton
    public void Import(string path)
    {
        var raw = Read(path);          // step varies
        var records = Parse(raw);       // step varies
        Validate(records);              // shared
        Save(records);                  // step varies
    }
    protected abstract string Read(string path);
    protected abstract List<Record> Parse(string raw);
    protected virtual void Validate(List<Record> r) { /* default */ }
    protected abstract void Save(List<Record> r);
}

